// ═══════════════════════════════════════════════════════════════════════════
// LOAD CONTEXT FROM SUPABASE - THE HIVE OS V4
// Charge: project, task, agents, project_memory, task_dependencies
// ═══════════════════════════════════════════════════════════════════════════

const axios = require('axios');

const SUPABASE_URL = 'https://vngkmmrglfajyccpbukh.supabase.co';
const SUPABASE_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InZuZ2ttbXJnbGZhanlj Y3BidWtoIiwicm9sZSI6ImFub24iLCJpYXQiOjE3MzQwMDc4NTMsImV4cCI6MjA0OTU4Mzg1M30.8RqLVy3H3zKqmPJX3g9xME8F8v_OxZoN7GvJ9z8q6oE';

const webhookData = $input.item.json.body || $input.item.json;
const projectId = webhookData.project_id;
const taskId = webhookData.task_id;
const userQuery = webhookData.query || webhookData.message || '';

if (!projectId || !taskId) {
  throw new Error('Missing required fields: project_id and task_id');
}

// ─────────────────────────────────────────────────────────────────────────
// 1. Load Project
// ─────────────────────────────────────────────────────────────────────────
const projectResponse = await axios.get(
  `${SUPABASE_URL}/rest/v1/projects?id=eq.${projectId}&select=*`,
  { headers: { 'apikey': SUPABASE_ANON_KEY, 'Authorization': `Bearer ${SUPABASE_ANON_KEY}` } }
);
const project = projectResponse.data[0];

// ─────────────────────────────────────────────────────────────────────────
// 2. Load Task
// ─────────────────────────────────────────────────────────────────────────
const taskResponse = await axios.get(
  `${SUPABASE_URL}/rest/v1/tasks?id=eq.${taskId}&select=*`,
  { headers: { 'apikey': SUPABASE_ANON_KEY, 'Authorization': `Bearer ${SUPABASE_ANON_KEY}` } }
);
const task = taskResponse.data[0];

// ─────────────────────────────────────────────────────────────────────────
// 3. Load Project Memory
// ─────────────────────────────────────────────────────────────────────────
const memoryContext = project.project_memory || {};

return [{
  json: {
    project,
    task,
    memory_context: memoryContext,
    user_query: userQuery,
    agent: 'MARCUS',
    timestamp: new Date().toISOString()
  }
}];

// ═══════════════════════════════════════════════════════════════════════════
// CHECK TASK DEPENDENCIES - THE HIVE OS V4
// Vérifie que toutes les dépendances de la tâche sont complètes
// ═══════════════════════════════════════════════════════════════════════════

const axios = require('axios');

const SUPABASE_URL = 'https://vngkmmrglfajyccpbukh.supabase.co';
const SUPABASE_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InZuZ2ttbXJnbGZhanlj Y3BidWtoIiwicm9sZSI6ImFub24iLCJpYXQiOjE3MzQwMDc4NTMsImV4cCI6MjA0OTU4Mzg1M30.8RqLVy3H3zKqmPJX3g9xME8F8v_OxZoN7GvJ9z8q6oE';

const context = $input.item.json;
const taskId = context.task.id;

// Vérifier les dépendances via SQL function
const checkResponse = await axios.post(
  `${SUPABASE_URL}/rest/v1/rpc/can_start_task`,
  { p_task_id: taskId },
  { headers: { 'apikey': SUPABASE_ANON_KEY, 'Authorization': `Bearer ${SUPABASE_ANON_KEY}`, 'Content-Type': 'application/json' } }
);

const canStart = Array.isArray(checkResponse.data) ? checkResponse.data[0] : checkResponse.data;

if (!canStart.ready) {
  // Récupérer les tâches bloquantes pour UI
  const blockingResponse = await axios.post(
    `${SUPABASE_URL}/rest/v1/rpc/get_blocking_tasks`,
    { p_task_id: taskId },
    { headers: { 'apikey': SUPABASE_ANON_KEY, 'Authorization': `Bearer ${SUPABASE_ANON_KEY}`, 'Content-Type': 'application/json' } }
  );

  return [{
    json: {
      ...context,
      dependencies_blocked: true,
      error_message: canStart.error_message,
      blocking_tasks: blockingResponse.data || [],
      ui_component: {
        type: 'DEPENDENCIES_BLOCKED',
        data: {
          error: canStart.error_message,
          blocking_tasks: blockingResponse.data || [],
          resolution: 'Complete the blocking tasks before starting this one.'
        }
      }
    }
  }];
}

return [{
  json: {
    ...context,
    dependencies_ok: true
  }
}];

// ═══════════════════════════════════════════════════════════════════════════
// CHECK STATE FLAGS - THE HIVE OS V4
// Valide les state flags requis avant d'exécuter des actions
// ═══════════════════════════════════════════════════════════════════════════

const context = $input.item.json;

// Si dépendances bloquées, passer directement
if (context.dependencies_blocked) {
  return [{ json: context }];
}

const stateFlags = context.project.state_flags || {};

// Vérifier les flags requis pour MARCUS (Trader)
const requiredFlags = {
  'meta_pixel_configured': 'Meta Pixel must be configured before launching campaigns',
  'google_ads_conversion_tracking': 'Google Ads conversion tracking must be set up'
};

const missingFlags = [];
for (const [flag, message] of Object.entries(requiredFlags)) {
  if (!stateFlags[flag]) {
    missingFlags.push({ flag, message });
  }
}

if (missingFlags.length > 0) {
  return [{
    json: {
      ...context,
      state_flags_missing: true,
      missing_flags: missingFlags,
      ui_component: {
        type: 'STATE_FLAGS_MISSING',
        data: {
          error: 'Required setup steps not completed',
          missing_flags: missingFlags,
          resolution: 'Complete the required setup before launching campaigns.'
        }
      }
    }
  }];
}

return [{
  json: {
    ...context,
    state_flags_ok: true
  }
}];

