// ═══════════════════════════════════════════════════════════════════════════
// PARSE AI RESPONSE + EXECUTE WRITE-BACKS
// ═══════════════════════════════════════════════════════════════════════════

const axios = require('axios');

const SUPABASE_URL = 'https://vngkmmrglfajyccpbukh.supabase.co';
const SUPABASE_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InZuZ2ttbXJnbGZhanlj Y3BidWtoIiwicm9sZSI6ImFub24iLCJpYXQiOjE3MzQwMDc4NTMsImV4cCI6MjA0OTU4Mzg1M30.8RqLVy3H3zKqmPJX3g9xME8F8v_OxZoN7GvJ9z8q6oE';

const context = $('Prepare MARCUS Context').item.json;
const aiResponse = $input.first().json;

// Si erreurs précédentes, retourner directement le composant UI
if (context.dependencies_blocked || context.state_flags_missing) {
  return [{
    json: {
      agent: 'MARCUS',
      timestamp: new Date().toISOString(),
      ui_component: context.ui_component,
      error: context.error_message || 'Prerequisites not met'
    }
  }];
}

const responseText = aiResponse.output || aiResponse.text || JSON.stringify(aiResponse);

// ─────────────────────────────────────────────────────────────────────────
// 1. Extraire les write-back commands du texte
// ─────────────────────────────────────────────────────────────────────────
const commands = [];

// Regex pour extraire les blocs JSON des commandes
const jsonBlockRegex = /```json\s*({[\s\S]*?})\s*```/g;
let match;
while ((match = jsonBlockRegex.exec(responseText)) !== null) {
  try {
    const command = JSON.parse(match[1]);
    commands.push(command);
  } catch (e) {
    // Ignorer les blocs JSON invalides
  }
}

// ─────────────────────────────────────────────────────────────────────────
// 2. Exécuter les write-backs
// ─────────────────────────────────────────────────────────────────────────
const executedCommands = [];

for (const cmd of commands) {
  try {
    if (cmd.type === 'MEMORY_WRITE' && cmd.memory_contribution) {
      // Mettre à jour project_memory
      const currentMemory = context.project.project_memory || {};
      const updatedMemory = {
        ...currentMemory,
        last_updated: new Date().toISOString(),
        last_updated_by: 'MARCUS',
        contributions: [
          ...(currentMemory.contributions || []),
          {
            timestamp: new Date().toISOString(),
            agent: 'MARCUS',
            ...cmd.memory_contribution
          }
        ].slice(-50) // Garder les 50 dernières contributions
      };

      await axios.patch(
        `${SUPABASE_URL}/rest/v1/projects?id=eq.${context.project.id}`,
        { project_memory: updatedMemory },
        { headers: { 'apikey': SUPABASE_ANON_KEY, 'Authorization': `Bearer ${SUPABASE_ANON_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' } }
      );

      executedCommands.push({ type: 'MEMORY_WRITE', status: 'success' });
    }

    if (cmd.type === 'UPDATE_TASK_STATUS') {
      const updateData = {};
      if (cmd.status) updateData.status = cmd.status;
      if (cmd.progress_percentage !== undefined) updateData.progress_percentage = cmd.progress_percentage;

      await axios.patch(
        `${SUPABASE_URL}/rest/v1/tasks?id=eq.${cmd.task_id || context.task.id}`,
        updateData,
        { headers: { 'apikey': SUPABASE_ANON_KEY, 'Authorization': `Bearer ${SUPABASE_ANON_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' } }
      );

      executedCommands.push({ type: 'UPDATE_TASK_STATUS', status: 'success' });
    }
  } catch (error) {
    executedCommands.push({ type: cmd.type, status: 'error', error: error.message });
  }
}

// ─────────────────────────────────────────────────────────────────────────
// 3. Extraire UI component si présent
// ─────────────────────────────────────────────────────────────────────────
const uiComponent = commands.find(cmd => cmd.type === 'UI_COMPONENT');

// ─────────────────────────────────────────────────────────────────────────
// 4. Retourner la réponse finale
// ─────────────────────────────────────────────────────────────────────────
return [{
  json: {
    agent: 'MARCUS',
    timestamp: new Date().toISOString(),
    response: responseText,
    ui_component: uiComponent || null,
    write_backs_executed: executedCommands,
    project_id: context.project.id,
    task_id: context.task.id
  }
}];
